    expect(registry.get(networkAtom)).toBe("sepolia")
  })

  it("can be set to 'mainnet'", () => {
    const registry = Registry.make()
    registry.set(networkAtom, "mainnet")
    expect(registry.get(networkAtom)).toBe("mainnet")
  })

